    @app.get("/analytics/documents/timeline")
    def analytics_timeline():
        status = (request.args.get("status") or "").strip().lower()
        interval = (request.args.get("interval") or "day").strip().lower()
        limit = min(int(request.args.get("limit") or 90), 365)

        if interval not in ("day", "month"):
            return jsonify({"error": "interval must be 'day' or 'month'"}), 400

        match = {}
        if status:
            match["status"] = status

        date_format = "%Y-%m-%d" if interval == "day" else "%Y-%m"

        pipeline = []
        if match:
            pipeline.append({"$match": match})
        pipeline += [
            {
                "$project": {
                    "bucket": {"$dateToString": {"format": date_format, "date": "$created_at"}},
                }
            },
            {"$group": {"_id": "$bucket", "count": {"$sum": 1}}},
            {"$project": {"_id": 0, "bucket": "$_id", "count": 1}},
            {"$sort": {"bucket": -1}},
            {"$limit": limit},
            {"$sort": {"bucket": 1}},
        ]
        res = list(docs.aggregate(pipeline))
        return jsonify({"items": res, "interval": interval}), 200

